def set_initial_star_ratings(apps, schema_editor):
    """
    Начальная установка рейтингов:
    - Опубликованные → 5 звёзд
    - is_no_news_found → 1 звезда
    - Остальные → NULL (не оценены)
    """
    NewsPost = apps.get_model('news', 'NewsPost')

    published_count = NewsPost.objects.filter(
        status='published', star_rating__isnull=True
    ).update(star_rating=5)

    no_news_count = NewsPost.objects.filter(
        is_no_news_found=True, star_rating__isnull=True
    ).update(star_rating=1)

    print(f"\n  → Опубликованные → 5★: {published_count}")
    print(f"  → Новостей не найдено → 1★: {no_news_count}")


